/**
 * M1 code for the delivery method used to complete a continuing education course.
 * - `"AUDIO"` — Audio recording
 * - `"CDROM"` — CD-ROM / offline media
 * - `"CLASS"` — In-person classroom
 * - `"ONLINE"` — Online / self-paced
 * - `"VIDCON"` — Video conference / live webinar
 * - `"VIDEO"` — Pre-recorded video
 */
export type DeliveryMethodCode = "AUDIO" | "CDROM" | "CLASS" | "ONLINE" | "VIDCON" | "VIDEO";